"""
mkt-christ commentary — Psalms 103–104
Run: python3 scripts/zc-christ-psalms-103-104.py

Key NT connections:
  Ps103:3  → Matt 9:2-7 (direct — forgives and heals; Son of Man authority)
  Ps103:13 → Luke 15:20 (direct — father's compassion; Prodigal Son)
  Ps103:19 → Matt 28:18; Rev 3:21 (direct — LORD's throne / Christ enthroned)
  Ps104:4  → Heb 1:7 (direct — angels as winds contrasted with the Son)
  Ps104:30 → John 20:22; 2 Cor 5:17 (direct — Spirit sent; new creation)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"103": {"1": "<p><span class=\"level\">theme</span> <em>Bless the LORD, O my soul, and all that is within me, bless his holy name!</em> The whole-person blessing of God — realized in Christ who loves the Lord with all his heart, soul, mind, and strength (Mark 12:30), perfectly fulfilling what Israel could only approximate. The holy name blessed here is the name Jesus declares to his Father: <em>I have manifested your name to the people whom you gave me</em> (John 17:6).</p>", "2": "<p><span class=\"level\">theme</span> <em>Bless the LORD, O my soul, and forget not all his benefits,</em> Forgetting none of God's benefits — the Eucharist as the church's act of remembrance: <em>do this in remembrance of me</em> (1 Cor 11:24-25). Christ institutes the meal precisely so his benefits — forgiveness, body broken, blood poured — are not forgotten. Every celebration of the Lord's Supper is the soul blessing God and forgetting none of his benefits.</p>", "3": "<p><span class=\"level\">direct</span> <em>who forgives all your iniquity, who heals all your diseases,</em> Forgiveness and healing united — the signature of Christ's ministry. Matthew 9:2-7: Jesus forgives the paralytic's sins, and when challenged asks, <em>which is easier, to say your sins are forgiven, or to say rise and walk?</em> — then heals him to prove the Son of Man has authority on earth to forgive sins. The conjunction of forgiveness and healing in Ps 103:3 is precisely enacted in Christ.</p>", "4": "<p><span class=\"level\">shadow</span> <em>who redeems your life from the pit, who crowns you with steadfast love and mercy,</em> Redemption from the pit — the resurrection as the ultimate pit-redemption. Christ descended into death (Eph 4:9) and was raised out of the pit: <em>God raised him up, loosing the pangs of death, because it was not possible for him to be held by it</em> (Acts 2:24). Those in him are crowned with the steadfast love and mercy Christ absorbed — <em>through him we have obtained access by faith into this grace</em> (Rom 5:2).</p>", "5": "<p><span class=\"level\">shadow</span> <em>who satisfies you with good so that your youth is renewed like the eagle's.</em> Youth renewed like the eagle — the resurrection transformation. <em>If the Spirit of him who raised Jesus from the dead dwells in you, he who raised Christ Jesus from the dead will also give life to your mortal bodies through his Spirit who dwells in you</em> (Rom 8:11). The renewal of youth is not cosmetic but ontological — the new creation body inaugurated in Christ's resurrection.</p>", "6": "<p><span class=\"level\">shadow</span> <em>The LORD works righteousness and justice for all who are oppressed.</em> Righteousness and justice for the oppressed — the Nazareth manifesto: <em>The Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor... to set at liberty those who are oppressed</em> (Luke 4:18, citing Isa 61:1). Christ is the LORD working righteousness for the oppressed, fulfilling the prophetic vision of Ps 103:6 in his own person and ministry.</p>", "7": "<p><span class=\"level\">type</span> <em>He made known his ways to Moses, his acts to the people of Israel.</em> God's ways known to Moses — fulfilled and surpassed in Christ: <em>the law was given through Moses; grace and truth came through Jesus Christ</em> (John 1:17). The mediator of the law who spoke with God face to face (Exod 33:11) is superseded by the one who is the face of God (2 Cor 4:6) and the mediator of the new covenant (Heb 9:15).</p>", "8": "<p><span class=\"level\">revelation of God</span> <em>The LORD is merciful and gracious, slow to anger and abounding in steadfast love.</em> The covenant name of God (Exod 34:6-7) — which Christ makes visible. <em>God, being rich in mercy, because of the great love with which he loved us, even when we were dead in our trespasses, made us alive together with Christ</em> (Eph 2:4-5). The divine character defined in Ps 103:8 is the character displayed at the cross and in the resurrection.</p>", "9": "<p><span class=\"level\">shadow</span> <em>He will not always chide, nor will he keep his anger forever.</em> The anger that does not last forever — the atonement makes this possible without compromising justice. God's wrath is satisfied in Christ (Rom 3:25 — propitiation) so that he does not chide forever. <em>In overflowing anger for a moment I hid my face from you, but with everlasting love I will have compassion on you</em> (Isa 54:8) — the moment of the cross gives way to everlasting compassion.</p>", "10": "<p><span class=\"level\">shadow</span> <em>He does not deal with us according to our sins, nor repay us according to our iniquities.</em> Grace exceeding deserved punishment — the doctrine of justification. <em>For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God</em> (2 Cor 5:21). God does not deal with believers according to their sins because Christ was dealt with according to those sins on their behalf. The not-dealing is grounded in the substitution.</p>", "11": "<p><span class=\"level\">revelation of God</span> <em>For as high as the heavens are above the earth, so great is his steadfast love toward those who fear him;</em> The immeasurable love — Paul reaches for the same cosmic scale: <em>I pray that you, being rooted and grounded in love, may have strength to comprehend with all the saints what is the breadth and length and height and depth, and to know the love of Christ that surpasses knowledge</em> (Eph 3:17-19). The heavens-above-earth image is the inadequate metaphor Paul tries to exceed.</p>", "12": "<p><span class=\"level\">shadow</span> <em>as far as the east is from the west, so far does he remove our transgressions from us.</em> Total removal of transgressions — the irreversible forgiveness grounded in Christ's atonement. Paul's declaration: <em>there is therefore now no condemnation for those who are in Christ Jesus</em> (Rom 8:1). The infinite east-west distance is the distance the cross places between the believer and their sin. <em>He has delivered us from the domain of darkness</em> (Col 1:13) — a complete removal.</p>", "13": "<p><span class=\"level\">direct</span> <em>As a father shows compassion to his children, so the LORD shows compassion to those who fear him;</em> The fatherly compassion enacted in Christ's parable of the Prodigal Son (Luke 15:20): <em>But while he was still a long way off, his father saw him and felt compassion, and ran and embraced him and kissed him.</em> Jesus gives the parable to reveal the Father's heart — the running father of Luke 15 is the LORD of Ps 103:13 made visible in a story.</p>", "14": "<p><span class=\"level\">shadow</span> <em>For he knows our frame; he remembers that we are dust.</em> God knowing human frailty — the Incarnation is God not merely remembering but entering: <em>since the children share in flesh and blood, he himself likewise partook of the same things</em> (Heb 2:14). Christ knows our frame from the inside — he grew tired (John 4:6), wept (John 11:35), hungered (Matt 4:2), and died. His knowing is not theoretical but experiential.</p>", "15": "<p><span class=\"level\">shadow</span> <em>As for man, his days are like grass; he flourishes like a flower of the field;</em> Human transience like grass — 1 Pet 1:24 applies Isa 40:6-8 (same image) to the contrast between the fading flesh and the enduring word of God. Christ enters the transience of grass-like humanity and transforms it: his resurrection body is the firstfruits of the imperishable (1 Cor 15:42-44), the flowering of humanity that does not fade.</p>", "16": "<p><span class=\"level\">shadow</span> <em>for the wind passes over it, and it is gone, and its place knows it no more.</em> The passing wind and vanishing life — the transience that Christ redeems. <em>Your life is a vapor that appears for a little time and then vanishes</em> (James 4:14). But those in Christ do not merely vanish: <em>For this corruptible must put on the incorruptible, and this mortal must put on immortality</em> (1 Cor 15:53). The wind that blew Jesus into the tomb also came as the breath of the resurrection morning.</p>", "17": "<p><span class=\"level\">revelation of God</span> <em>But the steadfast love of the LORD is from everlasting to everlasting on those who fear him, and his righteousness to children's children,</em> Everlasting steadfast love — the love of God from which nothing can separate: <em>I am sure that neither death nor life... nor anything else in all creation, will be able to separate us from the love of God in Christ Jesus our Lord</em> (Rom 8:38-39). The from-everlasting-to-everlasting love is the love that sent the Son (John 3:16) and keeps all who are in him.</p>", "18": "<p><span class=\"level\">shadow</span> <em>to those who keep his covenant and remember to do his commandments.</em> Covenant-keeping as the condition of receiving steadfast love — fulfilled in Christ the perfect covenant-keeper. He kept every commandment (John 8:29 — <em>I always do the things that are pleasing to him</em>) and his obedience is imputed to those who are in him (Rom 5:19 — <em>by the one man's obedience the many will be made righteous</em>).</p>", "19": "<p><span class=\"level\">direct</span> <em>The LORD has established his throne in the heavens, and his kingdom rules over all.</em> The heavenly throne and universal kingdom — Christ's enthronement: <em>all authority in heaven and on earth has been given to me</em> (Matt 28:18). Revelation places Christ on the heavenly throne (Rev 3:21; 5:6-14) alongside the Father. The kingdom that rules over all is now the kingdom of the Son (Col 1:13 — <em>the kingdom of his beloved Son</em>).</p>", "20": "<p><span class=\"level\">shadow</span> <em>Bless the LORD, O you his angels, you mighty ones who do his word, obeying the voice of his word!</em> Angels obeying the voice of God's word — Christ is the Word (John 1:1). At his birth the angels proclaimed him (Luke 2:13-14); at the temptation they ministered to him (Matt 4:11); at the resurrection they announced him (Matt 28:2-7). The mighty angels who obey the voice of his word now obey the voice of the incarnate Word.</p>", "21": "<p><span class=\"level\">shadow</span> <em>Bless the LORD, all his hosts, his ministers who do his will!</em> All the heavenly hosts blessing and serving — the throne-room of Revelation: <em>ten thousand times ten thousand and thousands of thousands, saying with a loud voice, Worthy is the Lamb who was slain, to receive power and wealth and wisdom and might and honor and glory and blessing!</em> (Rev 5:11-12). The hosts who bless God bless him through the Lamb.</p>", "22": "<p><span class=\"level\">theme</span> <em>Bless the LORD, all his works, in all places of his dominion. Bless the LORD, O my soul!</em> All creation blessing the LORD — the eschatological worship of Rev 5:13: <em>every creature in heaven and on earth and under the earth and in the sea, and all that is in them, saying, To him who sits on the throne and to the Lamb be blessing and honor and glory and might forever and ever!</em> The Psalm's universal praise reaches its target: Christ and the Father, receiving the blessing of all creation.</p>"}, "104": {"1": "<p><span class=\"level\">revelation of God</span> <em>Bless the LORD, O my soul! O LORD my God, you are very great! You are clothed with splendor and majesty,</em> God clothed in splendor and majesty — the Transfiguration discloses this glory: <em>his face shone like the sun, and his clothes became white as light</em> (Matt 17:2). The resurrection appearance radiates the same divine splendor: <em>his appearance was like lightning, and his clothing white as snow</em> (Matt 28:3). The great God clothed in majesty is the Christ who was clothed in human flesh and then revealed his hidden glory.</p>", "2": "<p><span class=\"level\">revelation of God</span> <em>covering yourself with light as with a garment, stretching out the heavens like a tent.</em> God clothed in light — <em>God is light, and in him is no darkness at all</em> (1 John 1:5). Christ: <em>I am the light of the world</em> (John 8:12). The stretching out of the heavens is the creative act of the Word: <em>in the beginning was the Word... all things were made through him</em> (John 1:1,3). The tent stretched out is the tabernacle of the Incarnation — <em>he pitched his tent among us</em> (John 1:14).</p>", "3": "<p><span class=\"level\">shadow</span> <em>He lays the beams of his chambers on the waters; he makes the clouds his chariot; he rides on the wings of the wind;</em> God riding clouds and wind — Christ coming on the clouds: <em>they will see the Son of Man coming on the clouds of heaven with power and great glory</em> (Matt 24:30; Rev 1:7 — <em>behold, he is coming with the clouds, and every eye will see him</em>). The cloud-rider of Ps 104 is identified in the NT as the returning Christ.</p>", "4": "<p><span class=\"level\">direct</span> <em>he makes his messengers winds, his ministers a flame of fire.</em> Hebrews 1:7 quotes this verse directly to contrast angels with the Son: <em>Of the angels he says, He makes his angels winds, and his ministers a flame of fire. But of the Son he says, Your throne, O God, is forever and ever.</em> The angels who are like wind and fire are servants; the Son is the eternal God enthroned. Ps 104:4 establishes the angel-servant status that proves the Son's superiority.</p>", "5": "<p><span class=\"level\">shadow</span> <em>He set the earth on its foundations, so that it should never be moved.</em> The earth's foundations set by Christ the creator: <em>by him all things were created, in heaven and on earth, visible and invisible</em> (Col 1:16). Heb 1:10-12 quotes Ps 102:25-27 similarly — <em>you, Lord, laid the foundation of the earth in the beginning</em> — applying it to the Son. The one who set the earth's foundation now holds all things together (Col 1:17).</p>", "6": "<p><span class=\"level\">shadow</span> <em>You covered it with the deep as with a garment; the waters stood above the mountains.</em> The primordial waters — Genesis creation imagery that John echoes in the new creation. The Spirit hovering over the waters (Gen 1:2) is the Spirit Christ sends (John 20:22). The deep covered by waters becomes the deep that Christ commands (Mark 4:39) and the deep of death he descends into and rises from (Rom 10:7).</p>", "7": "<p><span class=\"level\">shadow</span> <em>At your rebuke they fled; at the sound of your thunder they took to flight.</em> Waters fleeing at God's rebuke — Christ rebuking the storm: <em>he rebuked the wind and the raging waves, and they ceased, and there was a great calm</em> (Luke 8:24). The waters of chaos that fled at creation's command flee again at the voice of the incarnate Creator. The disciples' question — <em>who then is this?</em> — is answered by Psalm 104.</p>", "8": "<p><span class=\"level\">shadow</span> <em>The mountains rose, the valleys sank down to the place that you appointed for them.</em> Mountains rising and valleys sinking — the ordering of creation by the Word. The eschatological reversal: <em>every valley shall be filled, and every mountain and hill shall be made low</em> (Luke 3:5, citing Isa 40:4) — the preparation for the coming of the Lord. The creator who raised mountains will level them for his own appearing.</p>", "9": "<p><span class=\"level\">shadow</span> <em>You set a boundary that they may not pass, so that they might not again cover the earth.</em> The boundary set for the waters — the covenant with creation (Gen 9:11). Christ fulfills the Noah sign: the rainbow covenant (Gen 9:13-17) is the type of the new covenant in his blood. He who set the boundary for the seas is the one who says of the church: <em>the gates of hell shall not prevail against it</em> (Matt 16:18) — another boundary that holds.</p>", "10": "<p><span class=\"level\">revelation of God</span> <em>You make springs gush forth in the valleys; they flow between the hills;</em> Springs in the valleys — the living water Christ gives: <em>the water that I will give him will become in him a spring of water welling up to eternal life</em> (John 4:14). The creator God who makes springs gush in the valley is the same Lord who offers the Samaritan woman water that springs up to eternal life. Creation's provision is a parable of the gospel.</p>", "11": "<p><span class=\"level\">shadow</span> <em>they give drink to every beast of the field; the wild donkeys quench their thirst.</em> Every creature given drink by God — the providential care that points to Christ's universal provision. <em>Look at the birds of the air: they neither sow nor reap nor gather into barns, and yet your heavenly Father feeds them</em> (Matt 6:26). The God who quenches the wild donkey's thirst is the Father Christ reveals, who cares for every creature.</p>", "12": "<p><span class=\"level\">shadow</span> <em>Beside them the birds of the heavens dwell; they sing among the branches.</em> Birds singing in the branches — the imagery Christ uses for the kingdom: <em>the kingdom of heaven is like a grain of mustard seed... it becomes a tree, so that the birds of the air come and make nests in its branches</em> (Matt 13:31-32). The birds singing in creation's branches are the type of the nations finding rest in the kingdom of God.</p>", "13": "<p><span class=\"level\">shadow</span> <em>From your lofty abode you water the mountains; the earth is satisfied with the fruit of your work.</em> Earth satisfied by God's fruit — the spiritual fruitfulness Christ produces: <em>I chose you and appointed you that you should go and bear fruit and that your fruit should abide</em> (John 15:16). The satisfied earth of Ps 104 is the type of the new creation where Christ's work produces permanent fruit that abides forever.</p>", "14": "<p><span class=\"level\">shadow</span> <em>You cause the grass to grow for the livestock and plants for man to cultivate, that he may bring forth food from the earth</em> God providing food through creation — fulfilled in Christ the bread of life. The grass-and-grain provision of Ps 104 is good; Christ surpasses it: <em>your fathers ate the manna in the wilderness, and they died... I am the living bread that came down from heaven. If anyone eats of this bread, he will live forever</em> (John 6:49-51).</p>", "15": "<p><span class=\"level\">shadow</span> <em>and wine to gladden the heart of man, oil to make his face shine and bread to strengthen man's heart.</em> Wine, oil, and bread — the eucharistic elements. Christ transforms ordinary wine (John 2:1-11 — the first miracle) and bread (the feeding miracles; the Last Supper) into the sacramental signs of the new covenant. The oil suggests anointing; Christ the Anointed One (Messiah) is himself the oil that makes the face shine (Ps 45:7 — anointed with the oil of gladness).</p>", "16": "<p><span class=\"level\">shadow</span> <em>The trees of the LORD are watered abundantly, the cedars of Lebanon that he planted.</em> Trees planted and watered by the LORD — the righteous flourishing like cedars (Ps 92:12). Christ plants the church (John 15:1-5 — I am the vine, you are the branches) and waters it through the Spirit. The tree planted by the LORD is the image of the disciple rooted in Christ, bearing fruit in season (Ps 1:3; John 15:16).</p>", "17": "<p><span class=\"level\">shadow</span> <em>In them the birds build their nests; the stork has her home in the fir trees.</em> Nesting birds finding home in God's trees — the kingdom parable again (Matt 13:31-32). Those who find their home in Christ find shelter in the one who is simultaneously the tree and the Creator who planted the tree. The nesting place is the <em>abiding</em> of John 15:4-5.</p>", "18": "<p><span class=\"level\">shadow</span> <em>The high mountains are for the wild goats; the rocks are a refuge for the rock badgers.</em> Rocky refuge for small creatures — God's providential care for the vulnerable. Christ: <em>not one sparrow will fall to the ground apart from your Father</em> (Matt 10:29). Every creature finding its refuge in the created order is a parable of every soul finding refuge in Christ the Rock (1 Cor 10:4).</p>", "19": "<p><span class=\"level\">shadow</span> <em>He made the moon to mark the seasons; the sun knows its time for setting.</em> Seasons and times ordered by God — the eschatological times ordered by Christ. <em>It is not for you to know times or seasons that the Father has fixed by his own authority</em> (Acts 1:7). The creator who set the moon and sun's times has fixed the day of Christ's return; as the sun knows its time, so the Son knows when the Father will send him again.</p>", "20": "<p><span class=\"level\">shadow</span> <em>You make darkness, and it is night, when all the beasts of the forest creep about.</em> Darkness and night — the realm of the enemy that Christ invaded. <em>The night is coming, when no one can work</em> (John 9:4); <em>the light shines in the darkness, and the darkness has not overcome it</em> (John 1:5). Christ is the light that came into the world's night; the beasts that creep in darkness are routed by his presence.</p>", "21": "<p><span class=\"level\">shadow</span> <em>The young lions roar for their prey, seeking their food from God.</em> Even predators seeking food from God — the providential care extended even to the violent. Christ: <em>he makes his sun rise on the evil and on the good, and sends rain on the just and on the unjust</em> (Matt 5:45). The common grace that feeds even lions is the goodness of the God Christ reveals — who sends rain on the fields of those who crucified him.</p>", "22": "<p><span class=\"level\">shadow</span> <em>When the sun rises, they steal away and lie down in their dens.</em> Darkness and light alternating — the rhythm of creation that Christ transforms. He is the light that makes the darkness retreat permanently: <em>the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb</em> (Rev 21:23). The day-and-night rhythm ends in the new creation where there is no night.</p>", "23": "<p><span class=\"level\">shadow</span> <em>Man goes out to his work and to his labor until the evening.</em> Human labor until evening — the workday Christ inhabited. He was a carpenter (Mark 6:3) who worked with his hands; in his ministry he said <em>I must work the works of him who sent me while it is day; night is coming, when no one can work</em> (John 9:4). The daily labor of the human being is the creation order Christ dignified by entering it.</p>", "24": "<p><span class=\"level\">revelation of God</span> <em>O LORD, how manifold are your works! In wisdom you have made them all; the earth is full of your creatures.</em> Creation made in wisdom — Christ is the wisdom of God (1 Cor 1:24; Col 2:3 — <em>in whom are hidden all the treasures of wisdom and knowledge</em>). Paul: <em>for by him all things were created, in heaven and on earth, visible and invisible</em> (Col 1:16). The manifold works of God are the works of the Son through whom and for whom all things exist (Col 1:16-17).</p>", "25": "<p><span class=\"level\">shadow</span> <em>Here is the sea, great and wide, which teems with creatures innumerable, living things both small and great.</em> The teeming sea — the harvest field of Christ's disciples. <em>Follow me, and I will make you fishers of men</em> (Matt 4:19). The sea teeming with creatures is the world teeming with people for whom Christ died; the net of the kingdom (Matt 13:47-50) gathers from this sea.</p>", "26": "<p><span class=\"level\">shadow</span> <em>There go the ships, and Leviathan, which you formed to play in it.</em> Leviathan playing in the sea — the chaos monster tamed and made a plaything of God. Christ conquers the ultimate Leviathan: <em>he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him</em> (Col 2:15). The serpent-dragon of Revelation (Rev 12:9; 20:2 — <em>the ancient serpent, who is the devil</em>) is defeated by the Lamb.</p>", "27": "<p><span class=\"level\">shadow</span> <em>These all look to you, to give them their food in due season.</em> All creation looking to God for provision — the posture Christ taught: <em>look at the birds of the air: they neither sow nor reap nor gather into barns, and yet your heavenly Father feeds them. Are you not of more value than they?</em> (Matt 6:26). The looking of every creature to God is the posture of faith Christ calls humans to adopt toward the Father.</p>", "28": "<p><span class=\"level\">shadow</span> <em>When you give it to them, they gather it up; when you open your hand, they are filled with good things.</em> God opening his hand to fill — the feeding miracles of Christ. He opens his hands in the wilderness (Matt 14:19 — taking the loaves, looking to heaven, blessing and breaking) and fills five thousand. He opens his hands on the cross to fill all who come to him: <em>Come, everyone who thirsts, come to the waters</em> (Isa 55:1).</p>", "29": "<p><span class=\"level\">shadow</span> <em>When you hide your face, they are dismayed; when you take away their breath, they die and return to their dust.</em> The hidden face causing death — Christ's experience at the cross: <em>My God, my God, why have you forsaken me?</em> (Matt 27:46). The hiding of the divine face and the withdrawal of breath are the depths Christ entered on behalf of all who face the dismay of dying. His death exhausts the dismay so that his people face death with the Spirit's breath within them.</p>", "30": "<p><span class=\"level\">direct</span> <em>When you send forth your Spirit, they are created, and you renew the face of the ground.</em> The Spirit sent to create and renew — Pentecost and the new creation. Christ breathes the Spirit on his disciples (John 20:22 — <em>he breathed on them and said, Receive the Holy Spirit</em>). The Spirit sent at Pentecost renews the face of the earth by creating the new covenant community: <em>if anyone is in Christ, he is a new creation</em> (2 Cor 5:17). The renewing Spirit of Ps 104:30 is the Spirit of Christ.</p>", "31": "<p><span class=\"level\">shadow</span> <em>May the glory of the LORD endure forever; may the LORD rejoice in his works,</em> The enduring glory of the LORD — Christ's glory that endures: <em>the glory that you have given me I have given to them</em> (John 17:22). The LORD who rejoices in his works rejoices in the new creation accomplished through Christ — <em>the joy that was set before him</em> (Heb 12:2) for which Christ endured the cross. Creation's joy and God's joy meet in the resurrection of the Son.</p>", "32": "<p><span class=\"level\">revelation of God</span> <em>who looks on the earth and it trembles, who touches the mountains and they smoke!</em> The earth trembling at God's look — the earthquake and darkness at the crucifixion (Matt 27:51-54), the earthquake at the resurrection (Matt 28:2). The earth recognizes its Creator even when humanity does not. The centurion's response — <em>truly this was the Son of God!</em> — is the human echo of the earth's trembling recognition.</p>", "33": "<p><span class=\"level\">theme</span> <em>I will sing to the LORD as long as I live; I will sing praise to my God while I have being.</em> Singing to God as long as I live — the eternal praise of those whose life is Christ: <em>to live is Christ, and to die is gain</em> (Phil 1:21). The praise that lasts as long as life lasts becomes, in Christ, eternal — for <em>I am the resurrection and the life... whoever lives and believes in me shall never die</em> (John 11:25-26). Endless living means endless singing.</p>", "34": "<p><span class=\"level\">theme</span> <em>May my meditation be pleasing to him, for I rejoice in the LORD.</em> Meditation pleasing to God — the prayer Christ taught: meditation on God's word and works, grounded in the one who is himself the Word (John 1:1). <em>Whatever is true... honorable... just... pure... lovely... commendable... think about these things</em> (Phil 4:8). The meditation pleasing to God has Christ as its ultimate content and source.</p>", "35": "<p><span class=\"level\">shadow</span> <em>Let sinners be consumed from the earth, and let the wicked be no more! Bless the LORD, O my soul! Praise the LORD!</em> Sinners consumed and the wicked no more — the eschatological cleansing of the new creation: <em>nothing unclean will ever enter it, nor anyone who does what is detestable or false, but only those who are written in the Lamb's book of life</em> (Rev 21:27). The final <em>Praise the LORD!</em> (Hallelujah) is the word of Revelation 19:1-6 at the consummation — all creation joining the <em>Hallelujah!</em> of Ps 104's closing word.</p>"}}

if __name__ == "__main__":
    book = "psalms"
    source = "mkt-christ"
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f"  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge")
